import xml.etree.ElementTree as ET

def parse_xml_config(file_path):
    tree = ET.parse(file_path)
    root = tree.getroot()
    config_dict = {}

    def traverse(node, current_dict):
        for child in node:
            if len(child) > 0:
                new_dict = {}
                traverse(child, new_dict)
                current_dict[child.tag] = new_dict
            else:
                current_dict[child.tag] = child.text

    traverse(root, config_dict)
    return config_dict